var breakpoints = (function () {
    "use strict";

    // Main object
    function e(config) {
        t.init(config);
    }

    // Internal object to handle functionality
    var t = {
        list: null,
        media: {},
        events: [],

        // Initialize with configuration and set up event listeners
        init: function (config) {
            t.list = config;

            // Add event listeners for responsive changes
            window.addEventListener("resize", t.poll);
            window.addEventListener("orientationchange", t.poll);
            window.addEventListener("load", t.poll);
            window.addEventListener("fullscreenchange", t.poll);
        },

        // Check if a breakpoint is active
        active: function (query) {
            if (!(query in t.media)) {
                let comparison, breakpointName, range, minWidth, maxWidth, unit;

                // Determine the query type and breakpoint name
                if (query.startsWith(">=")) {
                    comparison = "gte";
                    breakpointName = query.substr(2);
                } else if (query.startsWith("<=")) {
                    comparison = "lte";
                    breakpointName = query.substr(2);
                } else if (query.startsWith(">")) {
                    comparison = "gt";
                    breakpointName = query.substr(1);
                } else if (query.startsWith("<")) {
                    comparison = "lt";
                    breakpointName = query.substr(1);
                } else if (query.startsWith("!")) {
                    comparison = "not";
                    breakpointName = query.substr(1);
                } else {
                    comparison = "eq";
                    breakpointName = query;
                }

                // Fetch the range for the breakpoint
                if (breakpointName && breakpointName in t.list) {
                    range = t.list[breakpointName];

                    if (Array.isArray(range)) {
                        minWidth = parseInt(range[0]);
                        maxWidth = parseInt(range[1]);

                        unit = isNaN(minWidth)
                            ? range[1].substr(String(maxWidth).length)
                            : range[0].substr(String(minWidth).length);

                        if (isNaN(minWidth)) {
                            // Handle cases with no minimum width
                            switch (comparison) {
                                case "gte":
                                    t.media[query] = "screen";
                                    break;
                                case "lte":
                                    t.media[query] = `screen and (max-width: ${maxWidth}${unit})`;
                                    break;
                                case "gt":
                                    t.media[query] = `screen and (min-width: ${maxWidth + 1}${unit})`;
                                    break;
                                case "lt":
                                case "not":
                                    t.media[query] = `screen and (max-width: -1px)`;
                                    break;
                                default:
                                    t.media[query] = `screen and (max-width: ${maxWidth}${unit})`;
                                    break;
                            }
                        } else if (isNaN(maxWidth)) {
                            // Handle cases with no maximum width
                            switch (comparison) {
                                case "gte":
                                    t.media[query] = `screen and (min-width: ${minWidth}${unit})`;
                                    break;
                                case "lte":
                                    t.media[query] = "screen";
                                    break;
                                case "gt":
                                case "not":
                                    t.media[query] = `screen and (max-width: -1px)`;
                                    break;
                                case "lt":
                                    t.media[query] = `screen and (max-width: ${minWidth - 1}${unit})`;
                                    break;
                                default:
                                    t.media[query] = `screen and (min-width: ${minWidth}${unit})`;
                                    break;
                            }
                        } else {
                            // Handle cases with both min and max widths
                            switch (comparison) {
                                case "gte":
                                    t.media[query] = `screen and (min-width: ${minWidth}${unit})`;
                                    break;
                                case "lte":
                                    t.media[query] = `screen and (max-width: ${maxWidth}${unit})`;
                                    break;
                                case "gt":
                                    t.media[query] = `screen and (min-width: ${maxWidth + 1}${unit})`;
                                    break;
                                case "lt":
                                    t.media[query] = `screen and (max-width: ${minWidth - 1}${unit})`;
                                    break;
                                case "not":
                                    t.media[query] = `screen and (max-width: ${minWidth - 1}${unit}), screen and (min-width: ${maxWidth + 1}${unit})`;
                                    break;
                                default:
                                    t.media[query] = `screen and (min-width: ${minWidth}${unit}) and (max-width: ${maxWidth}${unit})`;
                                    break;
                            }
                        }
                    } else {
                        t.media[query] = range.startsWith("(") ? `screen and ${range}` : range;
                    }
                } else {
                    t.media[query] = false;
                }
            }

            return t.media[query] !== false && window.matchMedia(t.media[query]).matches;
        },

        // Register an event handler for a breakpoint
        on: function (query, handler) {
            t.events.push({ query, handler, state: false });
            if (t.active(query)) handler();
        },

        // Poll all registered events
        poll: function () {
            t.events.forEach(event => {
                const active = t.active(event.query);
                if (active && !event.state) {
                    event.state = true;
                    event.handler();
                } else if (!active && event.state) {
                    event.state = false;
                }
            });
        }
    };

    // Expose methods
    e._ = t;
    e.on = t.on;
    e.active = t.active;

    return e;
})();

// UMD (Universal Module Definition)
(function (global, factory) {
    if (typeof define === "function" && define.amd) {
        define([], factory);
    } else if (typeof exports === "object") {
        module.exports = factory();
    } else {
        global.breakpoints = factory();
    }
})(this, function () {
    return breakpoints;
});
